"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[4453],{59506(n,t,r){r.r(t),r.d(t,{assets:()=>s,contentTitle:()=>u,default:()=>p,frontMatter:()=>i,metadata:()=>e,toc:()=>d});const e=JSON.parse('{"id":"cpp20/abbreviated-templates","title":"\u7b80\u5199\u51fd\u6570\u6a21\u677f (Abbreviated Function Templates)","description":"C++20 \u7b80\u5199\u51fd\u6570\u6a21\u677f (Abbreviated Function Templates) \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp20/04-abbreviated-templates.md","sourceDirName":"cpp20","slug":"/cpp20/04-abbreviated-templates","permalink":"/LearnModernCpp/docs/cpp20/04-abbreviated-templates","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp20","permalink":"/LearnModernCpp/docs/tags/cpp-20"},{"inline":true,"label":"abbreviated_templates","permalink":"/LearnModernCpp/docs/tags/abbreviated-templates"}],"version":"current","sidebarPosition":5,"frontMatter":{"sidebar_position":5,"slug":"04-abbreviated-templates","title":"\u7b80\u5199\u51fd\u6570\u6a21\u677f (Abbreviated Function Templates)","description":"C++20 \u7b80\u5199\u51fd\u6570\u6a21\u677f (Abbreviated Function Templates) \u6559\u5b66\u793a\u4f8b","tags":["cpp20","abbreviated_templates"]},"sidebar":"docs","previous":{"title":"requires \u8868\u8fbe\u5f0f","permalink":"/LearnModernCpp/docs/cpp20/03-requires-expressions"},"next":{"title":"\u4e09\u8def\u6bd4\u8f83\u8fd0\u7b97\u7b26 (Spaceship Operator \u27fa)","permalink":"/LearnModernCpp/docs/cpp20/05-spaceship-operator"}}');var a=r(74848),o=r(28453);const i={sidebar_position:5,slug:"04-abbreviated-templates",title:"\u7b80\u5199\u51fd\u6570\u6a21\u677f (Abbreviated Function Templates)",description:"C++20 \u7b80\u5199\u51fd\u6570\u6a21\u677f (Abbreviated Function Templates) \u6559\u5b66\u793a\u4f8b",tags:["cpp20","abbreviated_templates"]},u="\u7b80\u5199\u51fd\u6570\u6a21\u677f (Abbreviated Function Templates)",s={},d=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function c(n){const t={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,o.R)(),...n.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"\u7b80\u5199\u51fd\u6570\u6a21\u677f-abbreviated-function-templates",children:"\u7b80\u5199\u51fd\u6570\u6a21\u677f (Abbreviated Function Templates)"})}),"\n",(0,a.jsx)(t.p,{children:"C++20 \u6807\u51c6\u5f15\u5165\u7684 \u7b80\u5199\u51fd\u6570\u6a21\u677f (Abbreviated Function Templates) \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,a.jsx)(t.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,a.jsx)(t.pre,{children:(0,a.jsx)(t.code,{className:"language-cpp",metastring:'title="cpp20/04_abbreviated_templates.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: \u7b80\u5199\u51fd\u6570\u6a21\u677f (Abbreviated Function Templates)\r\n * \u6240\u5c5e\u6807\u51c6: C++20\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: C++20 \u5141\u8bb8\u5728\u666e\u901a\u51fd\u6570\u53c2\u6570\u4e2d\u4f7f\u7528 auto\uff0c\r\n *          \u4f7f\u51fd\u6570\u81ea\u52a8\u6210\u4e3a\u6a21\u677f\u51fd\u6570\uff08\u7b80\u5199\u51fd\u6570\u6a21\u677f\uff09\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: \u7b80\u5316\u6a21\u677f\u51fd\u6570\u7684\u7f16\u5199\uff0c\u4e0d\u9700\u8981\u663e\u5f0f\u5199 template<typename T>\uff0c\r\n *             \u4f7f\u4ee3\u7801\u66f4\u7b80\u6d01\u3001\u66f4\u63a5\u8fd1\u6cdb\u578b\u7f16\u7a0b\u7684\u76f4\u89c9\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - void f(auto x) \u7b49\u4ef7\u4e8e template<typename T> void f(T x)\r\n *   - \u53ef\u4ee5\u4f7f\u7528 concept \u7ea6\u675f auto\uff08constrained auto\uff09\r\n *   - \u6bcf\u4e2a auto \u53c2\u6570\u5f15\u5165\u72ec\u7acb\u7684\u6a21\u677f\u53c2\u6570\r\n *   - \u4e0e Lambda \u4e2d\u7684 auto \u53c2\u6570\u7c7b\u4f3c\uff0c\u4f46\u7528\u4e8e\u666e\u901a\u51fd\u6570\r\n * ============================================================\r\n */\r\n\r\n#include <concepts>\r\n#include <iostream>\r\n#include <string>\r\n#include <vector>\r\n#include <type_traits>\r\n#include <numeric>\r\n\r\n// ===================== basic_usage() =====================\r\n\r\n// C++20 \u7b80\u5199\u51fd\u6570\u6a21\u677f\uff1aauto \u53c2\u6570\u4f7f\u51fd\u6570\u53d8\u6210\u6a21\u677f\r\nvoid print_value(auto value) {\r\n    std::cout << "\u503c: " << value << " (\u7c7b\u578b\u5927\u5c0f: " << sizeof(value) << " \u5b57\u8282)\\n";\r\n}\r\n\r\n// \u7b49\u4ef7\u7684\u4f20\u7edf\u6a21\u677f\u5199\u6cd5:\r\n// template<typename T>\r\n// void print_value(T value) {\r\n//     std::cout << "\u503c: " << value << " (\u7c7b\u578b\u5927\u5c0f: " << sizeof(value) << " \u5b57\u8282)\\n";\r\n// }\r\n\r\n// \u591a\u4e2a auto \u53c2\u6570 \u2014\u2014 \u6bcf\u4e2a auto \u662f\u72ec\u7acb\u7684\u6a21\u677f\u53c2\u6570\r\nauto add(auto a, auto b) {\r\n    return a + b;\r\n}\r\n// \u7b49\u4ef7\u4e8e:\r\n// template<typename T1, typename T2>\r\n// auto add(T1 a, T2 b) { return a + b; }\r\n\r\n// \u8fd4\u56de\u7c7b\u578b\u4e5f\u53ef\u4ee5\u7528 auto\uff08\u4e0e C++14 \u4e00\u81f4\uff09\r\nauto multiply(auto x, auto y) -> decltype(x * y) {\r\n    return x * y;\r\n}\r\n\r\nvoid basic_usage() {\r\n    std::cout << "--- \u57fa\u7840\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // \u7b80\u5199\u6a21\u677f\u81ea\u52a8\u63a8\u5bfc\u7c7b\u578b\r\n    std::cout << "-- auto \u53c2\u6570\u81ea\u52a8\u6210\u4e3a\u6a21\u677f --\\n";\r\n    print_value(42);\r\n    print_value(3.14);\r\n    print_value(std::string("Hello C++20"));\r\n    print_value(\'A\');\r\n\r\n    // \u4e0d\u540c\u7c7b\u578b\u53c2\u6570\u7684\u6df7\u5408\u8c03\u7528\r\n    std::cout << "\\n-- \u591a\u4e2a auto \u53c2\u6570\uff08\u72ec\u7acb\u6a21\u677f\u53c2\u6570\uff09 --\\n";\r\n    std::cout << "add(1, 2) = " << add(1, 2) << "\\n";\r\n    std::cout << "add(1, 2.5) = " << add(1, 2.5) << "\\n";  // int + double \u2192 double\r\n    std::cout << "add(string, string) = "\r\n              << add(std::string("Hello "), std::string("World")) << "\\n";\r\n\r\n    std::cout << "\\n-- \u8fd4\u56de\u7c7b\u578b\u63a8\u5bfc --\\n";\r\n    std::cout << "multiply(3, 4) = " << multiply(3, 4) << "\\n";\r\n    std::cout << "multiply(2.5, 4) = " << multiply(2.5, 4) << "\\n";\r\n}\r\n\r\n// ===================== advanced_usage() =====================\r\n\r\n// \u4f7f\u7528 concept \u7ea6\u675f\u7684 auto\uff08constrained auto\uff09\r\nvoid print_number(std::integral auto n) {\r\n    std::cout << "\u6574\u6570: " << n << "\\n";\r\n}\r\n\r\nvoid print_number(std::floating_point auto n) {\r\n    std::cout << "\u6d6e\u70b9\u6570: " << n << "\\n";\r\n}\r\n\r\n// constrained auto \u7528\u4e8e\u8fd4\u56de\u7c7b\u578b\r\nstd::integral auto compute_factorial(std::integral auto n) {\r\n    decltype(n) result = 1;\r\n    for (decltype(n) i = 2; i <= n; ++i) {\r\n        result *= i;\r\n    }\r\n    return result;\r\n}\r\n\r\n// \u6df7\u5408\uff1a\u90e8\u5206\u53c2\u6570\u4f7f\u7528 auto\uff0c\u90e8\u5206\u4f7f\u7528\u5177\u4f53\u7c7b\u578b\r\nvoid mixed_function(int count, auto value) {\r\n    for (int i = 0; i < count; ++i) {\r\n        std::cout << value << " ";\r\n    }\r\n    std::cout << "\\n";\r\n}\r\n\r\n// \u4e0e const auto& \u548c auto&& \u7ed3\u5408\r\nvoid inspect(const auto& value) {\r\n    std::cout << "const \u5f15\u7528, \u7c7b\u578b\u5927\u5c0f: " << sizeof(value) << "\\n";\r\n}\r\n\r\nvoid forward_and_print(auto&& value) {\r\n    // auto&& \u662f\u8f6c\u53d1\u5f15\u7528\uff08forwarding reference\uff09\r\n    if constexpr (std::is_lvalue_reference_v<decltype(value)>) {\r\n        std::cout << "\u63a5\u6536\u5230\u5de6\u503c\u5f15\u7528\\n";\r\n    } else {\r\n        std::cout << "\u63a5\u6536\u5230\u53f3\u503c\u5f15\u7528\\n";\r\n    }\r\n}\r\n\r\n// \u7b80\u5199\u6a21\u677f\u4e0e\u663e\u5f0f\u6a21\u677f\u8bed\u6cd5\u5bf9\u6bd4\r\n// \u7b80\u5199\u7248\u672c\uff1a\r\nauto max_of(auto a, auto b) {\r\n    return (a > b) ? a : b;\r\n}\r\n\r\n// \u5f53\u9700\u8981\u4e24\u4e2a\u53c2\u6570\u7c7b\u578b\u76f8\u540c\u65f6\uff0c\u7b80\u5199\u7248\u672c\u505a\u4e0d\u5230\u2014\u2014\u9700\u8981\u663e\u5f0f\u6a21\u677f\r\ntemplate<typename T>\r\nT max_same_type(T a, T b) {\r\n    return (a > b) ? a : b;\r\n}\r\n\r\n// \u4f7f\u7528 concept \u7ea6\u675f\u6765\u5b9e\u73b0"\u76f8\u540c\u7c7b\u578b"\u6548\u679c\r\nvoid print_pair(auto a, std::same_as<decltype(a)> auto b) {\r\n    std::cout << "\u914d\u5bf9: (" << a << ", " << b << ")\\n";\r\n}\r\n\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- \u9ad8\u7ea7\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // constrained auto \u91cd\u8f7d\u9009\u62e9\r\n    std::cout << "-- Constrained auto\uff08\u7ea6\u675f auto\uff09 --\\n";\r\n    print_number(42);       // \u8c03\u7528\u6574\u6570\u7248\u672c\r\n    print_number(3.14);     // \u8c03\u7528\u6d6e\u70b9\u7248\u672c\r\n    print_number(100L);     // \u8c03\u7528\u6574\u6570\u7248\u672c\uff08long \u4e5f\u662f integral\uff09\r\n\r\n    std::cout << "\\n-- constrained auto \u8fd4\u56de\u7c7b\u578b --\\n";\r\n    std::cout << "5! = " << compute_factorial(5) << "\\n";\r\n    std::cout << "10! = " << compute_factorial(10) << "\\n";\r\n\r\n    // \u6df7\u5408\u53c2\u6570\r\n    std::cout << "\\n-- \u6df7\u5408\u5177\u4f53\u7c7b\u578b\u548c auto --\\n";\r\n    mixed_function(3, "hello");\r\n    mixed_function(2, 42);\r\n\r\n    // const auto& \u548c auto&&\r\n    std::cout << "\\n-- const auto& \u548c auto&& --\\n";\r\n    int x = 10;\r\n    inspect(x);\r\n    inspect(std::string("test"));\r\n\r\n    forward_and_print(x);          // \u5de6\u503c\r\n    forward_and_print(42);         // \u53f3\u503c\r\n    forward_and_print(std::string("temp"));  // \u53f3\u503c\r\n\r\n    // \u7ea6\u675f\u76f8\u540c\u7c7b\u578b\r\n    std::cout << "\\n-- \u786e\u4fdd\u53c2\u6570\u7c7b\u578b\u76f8\u540c --\\n";\r\n    print_pair(1, 2);\r\n    print_pair(std::string("a"), std::string("b"));\r\n    // print_pair(1, 2.0);  // \u7f16\u8bd1\u9519\u8bef\uff01\u7c7b\u578b\u4e0d\u540c\r\n}\r\n\r\n// ===================== pitfalls() =====================\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- \u6613\u9519\u70b9 ---\\n\\n";\r\n\r\n    // \u9677\u96311\uff1a\u6bcf\u4e2a auto \u662f\u72ec\u7acb\u7684\u6a21\u677f\u53c2\u6570\r\n    std::cout << "1. \u6bcf\u4e2a auto \u5f15\u5165\u72ec\u7acb\u7684\u6a21\u677f\u53c2\u6570:\\n";\r\n    std::cout << "   void f(auto a, auto b) \u4e2d a \u548c b \u53ef\u4ee5\u662f\u4e0d\u540c\u7c7b\u578b\\n";\r\n    std::cout << "   \u5982\u679c\u9700\u8981\u76f8\u540c\u7c7b\u578b\uff0c\u4f7f\u7528\u663e\u5f0f template<typename T> void f(T a, T b)\\n";\r\n    std::cout << "   \u793a\u4f8b: add(1, 2.5) \u5408\u6cd5\uff0c\u56e0\u4e3a auto a=int, auto b=double\\n\\n";\r\n\r\n    // \u9677\u96312\uff1a\u7b80\u5199\u6a21\u677f\u4e0d\u80fd\u6307\u5b9a\u6a21\u677f\u53c2\u6570\r\n    std::cout << "2. \u7b80\u5199\u6a21\u677f\u65e0\u6cd5\u663e\u5f0f\u6307\u5b9a\u6a21\u677f\u53c2\u6570:\\n";\r\n    std::cout << "   void f(auto x) \u4e0d\u80fd\u5199\u6210 f<int>(42)\\n";\r\n    std::cout << "   \u5982\u9700\u663e\u5f0f\u6307\u5b9a\uff0c\u5fc5\u987b\u7528\u4f20\u7edf template<typename T> \u8bed\u6cd5\\n\\n";\r\n\r\n    // \u9677\u96313\uff1aauto \u53c2\u6570\u7684\u7c7b\u578b\u7531\u8c03\u7528\u8005\u51b3\u5b9a\r\n    std::cout << "3. \u6bcf\u4e2a\u4e0d\u540c\u7c7b\u578b\u7684\u8c03\u7528\u90fd\u4f1a\u5b9e\u4f8b\u5316\u4e0d\u540c\u7248\u672c:\\n";\r\n    auto show_type = [](auto x) {\r\n        std::cout << "   \u503c: " << x << "\\n";\r\n    };\r\n    show_type(42);\r\n    show_type(3.14);\r\n\r\n    // \u9677\u96314\uff1a\u5728\u7c7b\u6210\u5458\u51fd\u6570\u4e2d\u4f7f\u7528 auto \u53c2\u6570\r\n    std::cout << "\\n4. \u7c7b\u7684\u975e\u9759\u6001\u6210\u5458\u51fd\u6570\u4e2d\uff0cauto \u53c2\u6570\u4f7f\u5176\u6210\u4e3a\u6210\u5458\u51fd\u6570\u6a21\u677f\\n";\r\n    std::cout << "   \u6ce8\u610f\uff1a\u865a\u51fd\u6570\u4e0d\u80fd\u662f\u6a21\u677f\uff0c\u6240\u4ee5\u865a\u51fd\u6570\u4e0d\u80fd\u4f7f\u7528 auto \u53c2\u6570\\n";\r\n\r\n    // \u6f14\u793a\uff1a\u7b80\u5199\u6a21\u677f\u4e0e Lambda \u7684\u533a\u522b\r\n    std::cout << "\\n5. \u7b80\u5199\u51fd\u6570\u6a21\u677f vs Lambda:\\n";\r\n    std::cout << "   Lambda: auto f = [](auto x) {};  // C++14 \u5c31\u652f\u6301\\n";\r\n    std::cout << "   \u51fd\u6570:   void f(auto x) {}        // C++20 \u65b0\u589e\\n";\r\n    std::cout << "   \u4e24\u8005\u90fd\u4f1a\u751f\u6210\u6a21\u677f\uff0c\u4f46\u51fd\u6570\u53ef\u4ee5\u91cd\u8f7d\uff0cLambda \u4e0d\u884c\\n";\r\n}\r\n\r\n// ===================== main() =====================\r\nint main() {\r\n    std::cout << "===== \u7b80\u5199\u51fd\u6570\u6a21\u677f - C++20 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,a.jsx)(t.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,a.jsxs)(t.ul,{children:["\n",(0,a.jsx)(t.li,{children:(0,a.jsx)(t.a,{href:"https://en.cppreference.com/w/cpp/language/function_template#Abbreviated_function_template",children:"cppreference: \u7b80\u5199\u51fd\u6570\u6a21\u677f (Abbreviated Function Templates)"})}),"\n"]})]})}function p(n={}){const{wrapper:t}={...(0,o.R)(),...n.components};return t?(0,a.jsx)(t,{...n,children:(0,a.jsx)(c,{...n})}):c(n)}},28453(n,t,r){r.d(t,{R:()=>i,x:()=>u});var e=r(96540);const a={},o=e.createContext(a);function i(n){const t=e.useContext(o);return e.useMemo(function(){return"function"==typeof n?n(t):{...t,...n}},[t,n])}function u(n){let t;return t=n.disableParentContext?"function"==typeof n.components?n.components(a):n.components||a:i(n.components),e.createElement(o.Provider,{value:t},n.children)}}}]);